import java.lang.annotation.*;
import java.lang.reflect.*;
import java.util.*;

@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.METHOD)
@interface GetMapping { String value(); }

@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.METHOD)
@interface PostMapping { String value(); }

@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.METHOD)
@interface DeleteMapping { String value(); }

public class BookController {
    private List<String> books = new ArrayList<>(Arrays.asList("Java", "Spring", "Docker"));

    @GetMapping("/books")
    public String getAllBooks() {
        return books.toString();
    }

    @PostMapping("/books")
    public String addBook(String title) {
        books.add(title);
        return "Book '" + title + "' added";
    }

    @DeleteMapping("/books")
    public String clearBooks() {
        books.clear();
        return "All books removed";
    }
}

