import java.util.*;

public class QueryStringParser {

    public Map<String, String> parse(String queryString) {
        // TODO: Parse 'key1=val1&key2=val2' into a map
        // Handle empty queryString gracefully
        return new LinkedHashMap<>();
    }

    public String getParam(Map<String, String> params, String key, String defaultValue) {
        return params.getOrDefault(key, defaultValue);
    }

    public int getIntParam(Map<String, String> params, String key, int defaultValue) {
        String val = params.get(key);
        if (val == null) return defaultValue;
        try { return Integer.parseInt(val); }
        catch (NumberFormatException e) { return defaultValue; }
    }
}

public class ArticleSearchController {
    private List<String> articles = Arrays.asList(
        "Java Guide", "Spring Boot Tutorial", "Docker Basics",
        "Kubernetes Intro", "React Fundamentals", "PostgreSQL Tips"
    );

    public List<String> search(Map<String, String> params) {
        String keyword = params.getOrDefault("q", "").toLowerCase();
        int page = Integer.parseInt(params.getOrDefault("page", "0"));
        int size = Integer.parseInt(params.getOrDefault("size", "3"));

        List<String> filtered = new ArrayList<>();
        for (String article : articles) {
            if (keyword.isEmpty() || article.toLowerCase().contains(keyword)) {
                filtered.add(article);
            }
        }

        int start = page * size;
        int end = Math.min(start + size, filtered.size());
        return start >= filtered.size() ? new ArrayList<>() : filtered.subList(start, end);
    }
}

public class Main {
    public static void main(String[] args) {
        QueryStringParser parser = new QueryStringParser();
        ArticleSearchController controller = new ArticleSearchController();

        String query1 = "page=0&size=3";
        String query2 = "q=java&page=0&size=5";
        String query3 = "q=spring&size=2";

        System.out.println("All (page 0, size 3): " + controller.search(parser.parse(query1)));
        System.out.println("Search 'java': " + controller.search(parser.parse(query2)));
        System.out.println("Search 'spring': " + controller.search(parser.parse(query3)));
    }
}
